    _img_dirs_extra = sorted({_os_img.path.dirname(p) for p in _img_paths if p})
    if _img_paths:
        log(DEBUG_LOG, 'L' + str(idx) + ' inline imgs=' + str(len(_img_paths)))
    extra_dirs = (extra_dirs or []) + _img_dirs_extra if '_img_dirs_extra' in dir() else (extra_dirs or [])
    reply = run_codex(prompt, priv, extra_dirs=extra_dirs, image_paths=_img_paths)
    # BOT_PROTECTIONS_MSKAI_V1 — refuse destructive blocks before exec.
    if 'reply' in dir() and reply:
        _eg_pat = _re_protect.compile(r"(?:python3\s*-?\s*<<\s*['\"]?(?:PY[A-Z0-9]*)['\"]?\s*\n(.*?)\nPY[A-Z0-9]*\b)|(?:bash\s*-l?c\s*<<\s*['\"]?(?:SH[A-Z0-9]*)['\"]?\s*\n(.*?)\nSH[A-Z0-9]*\b)|(?:bash\s+-l?c\s+'([^']{2,2000})')", _re_protect.S)
        _danger = []
        for _m in _eg_pat.finditer(reply):
            _body = next((g for g in _m.groups() if g), "")
            _bad, _why = _is_dangerous_protect(_body)
            if _bad: _danger.append(_why)
        if _danger:
            log(ERR_LOG, f"L{idx} EXEC_GUARD blocked: {_danger[:3]}")
            try:
                if 'post_reply_chunked' in globals(): post_reply_chunked(chat_id, '⚠️ I tried to run a command that looked destructive and refused.')
                else: post_reply(chat_id, '⚠️ I tried to run a command that looked destructive and refused.')
            except Exception: pass
            return
